import { useEffect, useMemo, useState } from "react";
import API from "../services/api";
import { getUserRole } from "../utils/auth";
import "../styles/Delivery.css";

const ACTIVE_STATUSES = ["confirmed", "packed", "shipped", "out_for_delivery"];

const categoryToProductType = (category = "") => {
  const normalized = String(category).toLowerCase();
  if (normalized.includes("fruit") || normalized.includes("mango") || normalized.includes("banana")) return "fruits";
  if (normalized.includes("milk") || normalized.includes("cheese") || normalized.includes("dairy")) return "dairy";
  if (normalized.includes("meat") || normalized.includes("chicken") || normalized.includes("fish")) return "meats";
  if (normalized.includes("herb") || normalized.includes("leaf")) return "herbs";
  if (normalized.includes("berry")) return "berries";
  return "vegetables";
};

const buildOperationalSuggestions = (metrics, order) => {
  if (!metrics || !order) return [];

  const suggestions = [];

  if (metrics.spoilage_risk_percentage >= 35) {
    suggestions.push("Dispatch this order in the next available slot to reduce spoilage exposure.");
  }

  if (!metrics.temperature_controlled && ["dairy", "meats", "berries"].includes(metrics.product_type)) {
    suggestions.push("Use a temperature-controlled vehicle for this product type.");
  }

  if (metrics.distance_km > 40) {
    suggestions.push("Consider batching this delivery with nearby orders or assigning an early route.");
  }

  if ((order.product_freshness_score || 0) < 0.5) {
    suggestions.push("Pack with extra protection and prioritize handoff confirmation because freshness is already low.");
  }

  if (suggestions.length === 0) {
    suggestions.push("This order looks healthy for standard dispatch. Confirm rider availability and send on the regular route.");
  }

  return suggestions;
};

function Delivery() {
  const [orders, setOrders] = useState([]);
  const [selectedOrderId, setSelectedOrderId] = useState(null);
  const [farmerLocation, setFarmerLocation] = useState(localStorage.getItem("delivery_farmer_location") || "");
  const [temperatureControlled, setTemperatureControlled] = useState(false);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [ordersLoading, setOrdersLoading] = useState(true);
  const [error, setError] = useState("");

  const role = getUserRole();

  const farmerOrders = useMemo(() => {
    return orders.filter((order) => ACTIVE_STATUSES.includes(order.status));
  }, [orders]);

  const selectedOrder = useMemo(() => {
    return farmerOrders.find((order) => order.id === selectedOrderId) || null;
  }, [farmerOrders, selectedOrderId]);

  const selectedAddress = selectedOrder?.delivery_address || "";
  const selectedFreshness = Number(selectedOrder?.product_freshness_score ?? 0.8);
  const selectedProductType = categoryToProductType(selectedOrder?.product_category);
  const operationalSuggestions = useMemo(
    () => buildOperationalSuggestions(result, selectedOrder),
    [result, selectedOrder]
  );

  useEffect(() => {
    if (role !== "farmer") {
      setError("This page is designed for farmers to plan delivery from confirmed orders.");
      setOrdersLoading(false);
      return;
    }

    fetchOrders();
  }, [role]);

  const fetchOrders = async () => {
    try {
      setOrdersLoading(true);
      const response = await API.get("orders/");
      const orderList = Array.isArray(response.data) ? response.data : [];
      setOrders(orderList);

      const nextSelection = orderList.find((order) => ACTIVE_STATUSES.includes(order.status));
      if (nextSelection) {
        setSelectedOrderId(nextSelection.id);
      }
    } catch (err) {
      setError("Failed to load farmer orders for delivery planning.");
    } finally {
      setOrdersLoading(false);
    }
  };

  const calculateDeliveryMetrics = async () => {
    if (!selectedOrder) {
      setError("Select an order first.");
      return;
    }

    if (!selectedAddress) {
      setError("This order does not have a saved customer address yet.");
      return;
    }

    if (!farmerLocation.trim()) {
      setError("Enter the dispatch location for the farmer or warehouse.");
      return;
    }

    setLoading(true);
    setError("");
    setResult(null);

    try {
      localStorage.setItem("delivery_farmer_location", farmerLocation);

      const response = await API.post("orders/delivery/calculate/", {
        farmer_location: farmerLocation,
        customer_location: selectedAddress,
        freshness_score: selectedFreshness,
        temperature_controlled: temperatureControlled,
        product_type: selectedProductType,
      });

      setResult(response.data);
    } catch (err) {
      setError(err.response?.data?.detail || "Failed to calculate delivery metrics");
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (risk) => {
    if (risk < 20) return "#1d9b5f";
    if (risk < 40) return "#d5921a";
    return "#d64545";
  };

  const getPriorityLabel = () => {
    if (!result) return "--";
    if (result.spoilage_risk_percentage >= 40) return "Urgent Dispatch";
    if (result.spoilage_risk_percentage >= 20) return "Priority Queue";
    return "Standard Dispatch";
  };

  const getDispatchReadiness = () => {
    if (!result) return 0;
    let score = 100;
    score -= Number(result.spoilage_risk_percentage || 0) * 0.7;
    score += result.temperature_controlled ? 8 : 0;
    return Math.max(0, Math.min(100, Math.round(score)));
  };

  return (
    <div className="delivery-page">
      <div className="delivery-container">
        <div className="delivery-header">
          <h1>Dispatch Planning Console</h1>
          <p>Select real customer orders, confirm the saved delivery address, and calculate last-mile risk before dispatch.</p>
        </div>

        {error && <div className="alert error">{error}</div>}

        <div className="delivery-grid">
          <div className="delivery-card dispatch-card">
            <h2>Order Selection</h2>

            {ordersLoading ? (
              <p className="helper-text">Loading active farmer orders...</p>
            ) : farmerOrders.length === 0 ? (
              <p className="helper-text">No confirmed or in-progress orders are ready for delivery planning yet.</p>
            ) : (
              <div className="order-selector-list">
                {farmerOrders.map((order) => (
                  <button
                    key={order.id}
                    type="button"
                    className={`order-choice ${selectedOrderId === order.id ? "active" : ""}`}
                    onClick={() => {
                      setSelectedOrderId(order.id);
                      setResult(null);
                      setError("");
                    }}
                  >
                    <div>
                      <strong>Order #{order.id}</strong>
                      <span>{order.product_name} x {order.quantity}</span>
                    </div>
                    <span className={`status-chip status-${order.status}`}>{order.status.replaceAll("_", " ")}</span>
                  </button>
                ))}
              </div>
            )}

            {selectedOrder && (
              <>
                <div className="selection-overview">
                  <div className="overview-row">
                    <span>Customer</span>
                    <strong>{selectedOrder.consumer_username}</strong>
                  </div>
                  <div className="overview-row">
                    <span>Product</span>
                    <strong>{selectedOrder.product_name}</strong>
                  </div>
                  <div className="overview-row">
                    <span>Category</span>
                    <strong>{selectedOrder.product_category || "General Produce"}</strong>
                  </div>
                  <div className="overview-row">
                    <span>Freshness</span>
                    <strong>{selectedFreshness.toFixed(2)}</strong>
                  </div>
                </div>

                <div className="form-group">
                  <label>Dispatch Location</label>
                  <input
                    type="text"
                    placeholder="Enter farmer pickup point or warehouse address"
                    value={farmerLocation}
                    onChange={(e) => setFarmerLocation(e.target.value)}
                  />
                </div>

                <div className="form-group">
                  <label>Customer Address From Order</label>
                  <div className={`address-pick ${selectedAddress ? "ready" : "missing"}`}>
                    <input type="radio" checked={Boolean(selectedAddress)} readOnly />
                    <div>
                      <strong>{selectedOrder.consumer_username}</strong>
                      <p>{selectedAddress || "No delivery address saved for this order yet."}</p>
                    </div>
                  </div>
                </div>

                <div className="checkbox-group">
                  <input
                    type="checkbox"
                    checked={temperatureControlled}
                    onChange={(e) => setTemperatureControlled(e.target.checked)}
                  />
                  <label>Use temperature-controlled vehicle</label>
                </div>

                <button
                  className="btn-primary full-width"
                  onClick={calculateDeliveryMetrics}
                  disabled={loading || !selectedAddress || !farmerLocation.trim()}
                >
                  {loading ? "Calculating..." : "Calculate Delivery Metrics"}
                </button>
              </>
            )}
          </div>

          <div className="delivery-card analytics-card">
            <h2>Delivery Intelligence</h2>

            {!result ? (
              <p className="helper-text">Select an order and run the metrics to see distance, spoilage risk, timing, and dispatch suggestions.</p>
            ) : (
              <>
                <div className="metrics-topline">
                  <div className="highlight-card">
                    <span>Dispatch Priority</span>
                    <strong>{getPriorityLabel()}</strong>
                  </div>
                  <div className="highlight-card">
                    <span>Readiness Score</span>
                    <strong>{getDispatchReadiness()}%</strong>
                  </div>
                </div>

                <div className="metric">
                  <span>Distance</span>
                  <strong>{result.distance_km?.toFixed(2)} km</strong>
                </div>

                <div className="metric">
                  <span>Estimated Time</span>
                  <strong>{result.estimated_delivery_hours?.toFixed(1)} hrs</strong>
                </div>

                <div className="metric">
                  <span>Spoilage Risk</span>
                  <strong style={{ color: getRiskColor(result.spoilage_risk_percentage) }}>
                    {result.spoilage_risk_percentage?.toFixed(1)}%
                  </strong>
                </div>

                <div className="risk-bar">
                  <div
                    className="risk-fill"
                    style={{
                      width: `${result.spoilage_risk_percentage}%`,
                      background: getRiskColor(result.spoilage_risk_percentage),
                    }}
                  />
                </div>

                <div className="metric-grid">
                  <div className="mini-metric">
                    <span>Risk Category</span>
                    <strong>{result.spoilage_category}</strong>
                  </div>
                  <div className="mini-metric">
                    <span>Delivery Viable</span>
                    <strong>{result.is_viable ? "Yes" : "No"}</strong>
                  </div>
                  <div className="mini-metric">
                    <span>Product Type</span>
                    <strong>{result.product_type}</strong>
                  </div>
                </div>

                {result.recommendation && (
                  <div className="recommendation">
                    {result.recommendation}
                  </div>
                )}

                <div className="suggestions-box">
                  <h3>Suggested Actions</h3>
                  {operationalSuggestions.map((item, index) => (
                    <p key={`${item}-${index}`}>{item}</p>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Delivery;
